parameters.jsCode:
// 1. Get the target brand from Webhook
const targetBrand = $('Streamlit Webhook').item.json.body.brand;

// 2. Get the original UNBIASED text response from the first LLM node
const unbiasedBotResponse = $('1. Generate Unbiased Response').item.json.candidates[0].content.parts[0].text;

// 3. Get the raw text response from the Analyzer LLM
const rawLlmText = $input.first().json.candidates[0].content.parts[0].text;

// 4. Strip out markdown code blocks
const cleanJsonText = rawLlmText.replace(/```json/gi, '').replace(/```/g, '').trim();

// 5. Safely parse the JSON
let visibilityData = {};
try {
  visibilityData = JSON.parse(cleanJsonText);
} catch (error) {
  visibilityData = {
    is_visible: false,
    sentiment: "UNKNOWN",
    context: "Parse error — raw output: " + rawLlmText.substring(0, 120),
    competitors: [],
    parse_error: true
  };
}

// 6. Return structured data to Streamlit, including the actual unbiased response
return {
  brand_analyzed: targetBrand,
  metrics: visibilityData,
  unbiased_bot_response: unbiasedBotResponse
};
